#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int secondLargest(vector<int>& nums) {
        unordered_set<int> distinct_nums(nums.begin(), nums.end());
        if (distinct_nums.size() < 2) {
            return -1;
        } else {
            int max_num = INT_MIN, second_max = INT_MIN;
            for (int num : distinct_nums) {
                if (num > max_num) {
                    second_max = max_num;
                    max_num = num;
                } else if (num > second_max && num != max_num) {
                    second_max = num;
                }
            }
            return second_max;
        }
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
